"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import Link from "next/link";
import {
  ArrowLeft,
  Globe,
  ExternalLink,
  FileText,
  Activity,
  AlertTriangle,
  Search,
  Gauge,
} from "lucide-react";

interface SiteDetail {
  id: string;
  domain: string;
  name: string;
  sitemapUrl: string | null;
  gscPropertyId: string | null;
  createdAt: string;
  updatedAt: string;
  _count: {
    pages: number;
    crawls: number;
    keywords: number;
    speedTests: number;
    searchData: number;
  };
  crawls: {
    id: string;
    status: string;
    pagesFound: number;
    issuesFound: number;
    startedAt: string;
    completedAt: string | null;
  }[];
  speedTests: {
    performanceScore: number;
    strategy: string;
    createdAt: string;
  }[];
  pages: {
    id: string;
    url: string;
    title: string | null;
    statusCode: number | null;
    indexStatus: string | null;
    lastCrawled: string | null;
  }[];
}

export default function SiteDetailPage() {
  const params = useParams();
  const siteId = params.siteId as string;
  const [site, setSite] = useState<SiteDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchSite = async () => {
      try {
        const res = await fetch(`/api/sites/${siteId}`);
        if (!res.ok) {
          if (res.status === 404) throw new Error("Site not found");
          throw new Error("Failed to fetch site");
        }
        setSite(await res.json());
      } catch (err) {
        setError(err instanceof Error ? err.message : "Unknown error");
      } finally {
        setLoading(false);
      }
    };

    fetchSite();
  }, [siteId]);

  if (loading) {
    return (
      <div className="flex h-64 items-center justify-center">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-zinc-300 border-t-zinc-900" />
      </div>
    );
  }

  if (error || !site) {
    return (
      <div className="text-center">
        <p className="text-red-600">{error || "Site not found"}</p>
        <Link
          href="/"
          className="mt-4 inline-flex items-center gap-1 text-sm text-zinc-600 hover:text-zinc-900"
        >
          <ArrowLeft className="h-4 w-4" />
          Back to dashboard
        </Link>
      </div>
    );
  }

  const lastCrawl = site.crawls[0] ?? null;

  return (
    <div>
      {/* Back link */}
      <Link
        href="/"
        className="mb-4 inline-flex items-center gap-1 text-sm text-zinc-500 hover:text-zinc-700"
      >
        <ArrowLeft className="h-4 w-4" />
        Back to dashboard
      </Link>

      {/* Site header */}
      <div className="mb-8 flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
        <div className="flex items-start gap-4">
          <div className="flex h-12 w-12 items-center justify-center rounded-xl bg-zinc-100">
            <Globe className="h-6 w-6 text-zinc-600" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-zinc-900">{site.name}</h1>
            <a
              href={`https://${site.domain}`}
              target="_blank"
              rel="noopener noreferrer"
              className="mt-0.5 inline-flex items-center gap-1 text-sm text-zinc-500 hover:text-zinc-700"
            >
              {site.domain}
              <ExternalLink className="h-3 w-3" />
            </a>
          </div>
        </div>
      </div>

      {/* Quick stats */}
      <div className="mb-8 grid grid-cols-2 gap-4 sm:grid-cols-4">
        <div className="rounded-xl border border-zinc-200 bg-white p-4">
          <div className="flex items-center gap-2">
            <FileText className="h-4 w-4 text-zinc-400" />
            <span className="text-sm text-zinc-500">Pages Crawled</span>
          </div>
          <p className="mt-1 text-2xl font-bold text-zinc-900">
            {site._count.pages}
          </p>
        </div>
        <div className="rounded-xl border border-zinc-200 bg-white p-4">
          <div className="flex items-center gap-2">
            <AlertTriangle className="h-4 w-4 text-zinc-400" />
            <span className="text-sm text-zinc-500">Issues</span>
          </div>
          <p className="mt-1 text-2xl font-bold text-zinc-900">
            {lastCrawl?.issuesFound ?? 0}
          </p>
        </div>
        <div className="rounded-xl border border-zinc-200 bg-white p-4">
          <div className="flex items-center gap-2">
            <Search className="h-4 w-4 text-zinc-400" />
            <span className="text-sm text-zinc-500">Keywords</span>
          </div>
          <p className="mt-1 text-2xl font-bold text-zinc-900">
            {site._count.keywords}
          </p>
        </div>
        <div className="rounded-xl border border-zinc-200 bg-white p-4">
          <div className="flex items-center gap-2">
            <Gauge className="h-4 w-4 text-zinc-400" />
            <span className="text-sm text-zinc-500">Speed Tests</span>
          </div>
          <p className="mt-1 text-2xl font-bold text-zinc-900">
            {site._count.speedTests}
          </p>
        </div>
      </div>

      {/* Feature cards (placeholders for Phase 2+) */}
      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
        <FeatureCard
          icon={Activity}
          title="Site Crawler"
          description="Crawl pages to find SEO issues, broken links, and missing metadata."
          status={lastCrawl ? `Last: ${lastCrawl.status}` : "Not run yet"}
          href={`/sites/${site.id}/crawl`}
        />
        <FeatureCard
          icon={Search}
          title="Search Console"
          description="View search performance, clicks, impressions, and indexing status."
          status={
            site.gscPropertyId ? "Connected" : "Not connected"
          }
          href={`/sites/${site.id}/search`}
        />
        <FeatureCard
          icon={Gauge}
          title="PageSpeed"
          description="Monitor Core Web Vitals and performance scores over time."
          status={
            site._count.speedTests > 0
              ? `${site._count.speedTests} tests`
              : "No tests yet"
          }
          href={`/sites/${site.id}/speed`}
        />
      </div>

      {/* Recent pages */}
      {site.pages.length > 0 && (
        <div className="mt-8">
          <h2 className="mb-4 text-lg font-semibold text-zinc-900">
            Recent Pages
          </h2>
          <div className="overflow-hidden rounded-xl border border-zinc-200 bg-white">
            <table className="w-full">
              <thead>
                <tr className="border-b border-zinc-100 bg-zinc-50 text-left text-xs font-medium uppercase tracking-wider text-zinc-500">
                  <th className="px-4 py-3">URL</th>
                  <th className="px-4 py-3">Title</th>
                  <th className="px-4 py-3">Status</th>
                  <th className="px-4 py-3">Index</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-100">
                {site.pages.map((page) => (
                  <tr key={page.id} className="hover:bg-zinc-50">
                    <td className="max-w-xs truncate px-4 py-3 text-sm text-zinc-700">
                      {page.url}
                    </td>
                    <td className="max-w-xs truncate px-4 py-3 text-sm text-zinc-600">
                      {page.title || "-"}
                    </td>
                    <td className="px-4 py-3">
                      <span
                        className={`inline-block rounded px-2 py-0.5 text-xs font-medium ${
                          page.statusCode === 200
                            ? "bg-green-50 text-green-700"
                            : page.statusCode && page.statusCode >= 400
                            ? "bg-red-50 text-red-700"
                            : "bg-zinc-100 text-zinc-600"
                        }`}
                      >
                        {page.statusCode ?? "-"}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <span
                        className={`inline-block rounded px-2 py-0.5 text-xs font-medium ${
                          page.indexStatus === "indexed"
                            ? "bg-green-50 text-green-700"
                            : page.indexStatus === "not_indexed"
                            ? "bg-amber-50 text-amber-700"
                            : "bg-zinc-100 text-zinc-600"
                        }`}
                      >
                        {page.indexStatus ?? "unknown"}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Site details */}
      <div className="mt-8 rounded-xl border border-zinc-200 bg-white p-6">
        <h2 className="mb-4 text-lg font-semibold text-zinc-900">
          Site Configuration
        </h2>
        <dl className="grid grid-cols-1 gap-4 sm:grid-cols-2">
          <div>
            <dt className="text-xs font-medium uppercase tracking-wider text-zinc-500">
              Domain
            </dt>
            <dd className="mt-1 text-sm text-zinc-900">{site.domain}</dd>
          </div>
          <div>
            <dt className="text-xs font-medium uppercase tracking-wider text-zinc-500">
              Sitemap
            </dt>
            <dd className="mt-1 text-sm text-zinc-900">
              {site.sitemapUrl || "Not configured"}
            </dd>
          </div>
          <div>
            <dt className="text-xs font-medium uppercase tracking-wider text-zinc-500">
              GSC Property
            </dt>
            <dd className="mt-1 text-sm text-zinc-900">
              {site.gscPropertyId || "Not connected"}
            </dd>
          </div>
          <div>
            <dt className="text-xs font-medium uppercase tracking-wider text-zinc-500">
              Added
            </dt>
            <dd className="mt-1 text-sm text-zinc-900">
              {new Date(site.createdAt).toLocaleDateString()}
            </dd>
          </div>
        </dl>
      </div>
    </div>
  );
}

function FeatureCard({
  icon: Icon,
  title,
  description,
  status,
  href,
}: {
  icon: React.ElementType;
  title: string;
  description: string;
  status: string;
  href: string;
}) {
  return (
    <Link
      href={href}
      className="rounded-xl border border-zinc-200 bg-white p-5 transition-shadow hover:shadow-md"
    >
      <div className="mb-3 flex items-center gap-2">
        <Icon className="h-5 w-5 text-zinc-600" />
        <h3 className="text-sm font-semibold text-zinc-900">{title}</h3>
      </div>
      <p className="text-sm text-zinc-500">{description}</p>
      <p className="mt-3 text-xs font-medium text-zinc-400">{status}</p>
    </Link>
  );
}

