                            : page.statusCode && page.statusCode >= 400
                            ? "bg-red-50 text-red-700"
                            : "bg-zinc-100 text-zinc-600"
                        }`}
                      >
                        {page.statusCode ?? "-"}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <span
                        className={`inline-block rounded px-2 py-0.5 text-xs font-medium ${
                          page.indexStatus === "indexed"
                            ? "bg-green-50 text-green-700"
                            : page.indexStatus === "not_indexed"
                            ? "bg-amber-50 text-amber-700"
                            : "bg-zinc-100 text-zinc-600"
                        }`}
                      >
                        {page.indexStatus ?? "unknown"}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Site details */}
      <div className="mt-8 rounded-xl border border-zinc-200 bg-white p-6">
        <h2 className="mb-4 text-lg font-semibold text-zinc-900">
          Site Configuration
        </h2>
        <dl className="grid grid-cols-1 gap-4 sm:grid-cols-2">
          <div>
            <dt className="text-xs font-medium uppercase tracking-wider text-zinc-500">
              Domain
            </dt>
            <dd className="mt-1 text-sm text-zinc-900">{site.domain}</dd>
          </div>
          <div>
            <dt className="text-xs font-medium uppercase tracking-wider text-zinc-500">
              Sitemap
            </dt>
            <dd className="mt-1 text-sm text-zinc-900">
              {site.sitemapUrl || "Not configured"}
            </dd>
          </div>
          <div>
            <dt className="text-xs font-medium uppercase tracking-wider text-zinc-500">
              GSC Property
            </dt>
            <dd className="mt-1 text-sm text-zinc-900">
              {site.gscPropertyId || "Not connected"}
            </dd>
          </div>
          <div>
            <dt className="text-xs font-medium uppercase tracking-wider text-zinc-500">
              Added
            </dt>
            <dd className="mt-1 text-sm text-zinc-900">
              {new Date(site.createdAt).toLocaleDateString()}
            </dd>
          </div>
        </dl>
      </div>
    </div>
  );
}

function FeatureCard({
  icon: Icon,
  title,
  description,
  status,
  href,
}: {
  icon: React.ElementType;
  title: string;
  description: string;
  status: string;
  href: string;
}) {
  return (
    <Link
      href={href}
      className="rounded-xl border border-zinc-200 bg-white p-5 transition-shadow hover:shadow-md"
    >
      <div className="mb-3 flex items-center gap-2">
        <Icon className="h-5 w-5 text-zinc-600" />
        <h3 className="text-sm font-semibold text-zinc-900">{title}</h3>
      </div>
      <p className="text-sm text-zinc-500">{description}</p>
      <p className="mt-3 text-xs font-medium text-zinc-400">{status}</p>
    </Link>
  );
}

